def read_chunks(filepath, chunk_size=10_000):
    """Yield one DataFrame chunk at a time from a large CSV."""
    with open(filepath, "r") as f:
        reader = pd.read_csv(f, chunksize=chunk_size)
        for chunk in reader:
            yield chunk

def filter_chunk(chunks, condition):
    for chunk in chunks:
        yield chunk[condition(chunk)]

def transform_chunk(chunks, func):
