from pathlib import Path

def stream_jsonl(filepath):
    """Stream a JSON-lines file one record at a time."""
    with open(filepath, "r") as f:
        for line in f:
            yield json.loads(line)

def batch_records(records, batch_size=100_000):
    """Group records into batches for vectorized processing."""
    batch = []
    for record in records:
        batch.append(record)
        if len(batch) >= batch_size:
            yield pd.DataFrame(batch)
            batch.clear()
    if batch:
        yield pd.DataFrame(batch)

def compute_dau(log_dir):
    dau = defaultdict(set)  # date -> set of user_ids

    for log_file in sorted(Path(log_dir).glob("*.jsonl")):
        print(f"Processing {log_file.name}...")
        records = stream_jsonl(log_file)

        for batch in batch_records(records, batch_size=100_000):
            batch["date"] = pd.to_datetime(batch["timestamp"]).dt.date
            for _, row in batch[["date", "user_id"]].itertuples(index=False, name=None):
                # Note: in practice, use HyperLogLog for true out-of-core DAU
                dau[_].add(row)

    return {date: len(users) for date, users in dau.items()}

