from concurrent.futures import ThreadPoolExecutor

def prefetch_chunks(iterator, prefetch=2):
    """Prefetch up to N chunks ahead using a thread pool."""
    with ThreadPoolExecutor(max_workers=prefetch) as executor:
        futures = []
        for chunk in iterator:
            futures.append(executor.submit(lambda c: c, chunk))
            if len(futures) > prefetch:
                yield futures.pop(0).result()
        for f in futures:
            yield f.result()

import tempfile, shutil, os

def safe_pipeline(input_path, output_path):
    tmp = output_path + ".tmp"
    try:
        first = True
        for chunk in pd.read_csv(input_path, chunksize=50_000):
            chunk.to_csv(tmp, mode="w" if first else "a", header=first, index=False)
            first = False
        os.replace(tmp, output_path)  # Atomic on POSIX
    except Exception:
        if os.path.exists(tmp):
            os.remove(tmp)
        raise

